import { jsPDF } from "jspdf"
var font = '';
var callAddFont = function () {
this.addFileToVFS('NotoSerifBengali-VariableFont_wdth,wght-bold.ttf', font);
this.addFont('NotoSerifBengali-VariableFont_wdth,wght-bold.ttf', 'NotoSerifBengali-VariableFont_wdth,wght', 'bold');
};
jsPDF.API.events.push(['addFonts', callAddFont])
